#!/bin/bash
python3 - <<'ATPY'

import json, os, sys, time, mimetypes, uuid, urllib.request, urllib.error

API_KEY = os.environ.get("VAR_ELEVENLABS_API_KEY") or ""
WORK_DIR = os.environ.get("AT_WORK_DIR") or "/tmp"
ASSETS_DIR = os.environ.get("AT_ASSETS_DIR") or os.path.join(WORK_DIR, "assets")
VOICE_DIR = os.path.join(ASSETS_DIR, "voices")
BASE = "https://api.elevenlabs.io"

def die(msg, **extra):
    out = {"error": msg}
    out.update(extra)
    print(json.dumps(out)); sys.exit(0)

if not API_KEY:
    die("ElevenLabs API key not configured (set elevenlabs_api_key)")

def api(path, payload=None, method=None, raw=False, timeout=120):
    data = json.dumps(payload).encode() if payload is not None else None
    req = urllib.request.Request(BASE + path, data=data,
        method=method or ("POST" if data else "GET"),
        headers={"xi-api-key": API_KEY, "Content-Type": "application/json"})
    try:
        with urllib.request.urlopen(req, timeout=timeout) as r:
            return r.read() if raw else json.load(r)
    except urllib.error.HTTPError as e:
        die("ElevenLabs API error", status=e.code, body=e.read().decode(errors="replace")[:800])

def slugify(name):
    return name.strip().lower().replace(" ", "-")

def local_manifests():
    out = {}
    if os.path.isdir(VOICE_DIR):
        for f in os.listdir(VOICE_DIR):
            if f.endswith(".json"):
                try:
                    m = json.load(open(os.path.join(VOICE_DIR, f)))
                    if m.get("voice_id"):
                        out[m.get("slug") or slugify(m.get("name", ""))] = m
                except Exception:
                    pass
    return out

def resolve_voice(ref):
    """Voice reference: raw voice_id, library name, or account voice name."""
    if not ref:
        return ref
    mans = local_manifests()
    s = slugify(ref)
    if s in mans:
        return mans[s]["voice_id"]
    voices = (api("/v1/voices") or {}).get("voices", [])
    for v in voices:
        if v.get("voice_id") == ref:
            return ref
    for v in voices:
        if v.get("name", "").strip().lower() == ref.strip().lower():
            return v["voice_id"]
    # Assume it is a voice_id we could not list (workspace voices etc.)
    return ref

name = os.environ.get("ARG_NAME", "")
desc = os.environ.get("ARG_DESCRIPTION", "")
try:
    samples = json.loads(os.environ.get("ARG_SAMPLES", "[]"))
except Exception:
    samples = [s for s in os.environ.get("ARG_SAMPLES", "").split(",") if s.strip()]
if not name or not samples:
    die("name and samples are required")

# Materialize URLs to local files.
paths = []
for s in samples[:5]:
    s = s.strip()
    if s.startswith(("http://", "https://")):
        ext = os.path.splitext(s.split("?")[0])[1] or ".mp3"
        tmp = os.path.join(WORK_DIR, "voice-sample-%s%s" % (uuid.uuid4().hex[:8], ext))
        os.makedirs(WORK_DIR, exist_ok=True)
        with urllib.request.urlopen(s, timeout=300) as r, open(tmp, "wb") as f:
            f.write(r.read())
        paths.append(tmp)
    else:
        p = os.path.expanduser(s)
        if not os.path.isfile(p):
            die("sample not found: " + p)
        paths.append(p)

# Multipart form-data build (stdlib only).
boundary = "----atform" + uuid.uuid4().hex
body = bytearray()
def field(k, v):
    body.extend(("--%s\r\nContent-Disposition: form-data; name=\"%s\"\r\n\r\n%s\r\n" % (boundary, k, v)).encode())
field("name", name)
if desc:
    field("description", desc)
for p in paths:
    ctype = mimetypes.guess_type(p)[0] or "audio/mpeg"
    body.extend(("--%s\r\nContent-Disposition: form-data; name=\"files\"; filename=\"%s\"\r\nContent-Type: %s\r\n\r\n" % (boundary, os.path.basename(p), ctype)).encode())
    body.extend(open(p, "rb").read())
    body.extend(b"\r\n")
body.extend(("--%s--\r\n" % boundary).encode())

req = urllib.request.Request(BASE + "/v1/voices/add", data=bytes(body), method="POST",
    headers={"xi-api-key": API_KEY, "Content-Type": "multipart/form-data; boundary=" + boundary})
try:
    with urllib.request.urlopen(req, timeout=300) as r:
        res = json.load(r)
except urllib.error.HTTPError as e:
    die("ElevenLabs voice clone failed", status=e.code, body=e.read().decode(errors="replace")[:800])

voice_id = res.get("voice_id", "")
if not voice_id:
    die("no voice_id in response", raw=str(res)[:400])

os.makedirs(VOICE_DIR, exist_ok=True)
manifest = {"name": name, "slug": slugify(name), "voice_id": voice_id,
            "provider": "elevenlabs", "description": desc,
            "created_at": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())}
with open(os.path.join(VOICE_DIR, slugify(name) + ".json"), "w") as f:
    json.dump(manifest, f, indent=1)
print(json.dumps({"voice_id": voice_id, "name": name, "manifest": manifest}))

