text = os.environ.get("ARG_TEXT", "")
voice = os.environ.get("ARG_VOICE", "")
model_id = os.environ.get("ARG_MODEL_ID", "eleven_multilingual_v2")
if not text or not voice:
    die("text and voice are required")

def num(key, default):
    try:
        return float(os.environ.get(key, ""))
    except Exception:
        return default

